import timefrom picamera2 import Picamera2from libcamera import Transformprint("Warming up camera sensor...")# Initialize modern camera architecturepicam2 = Picamera2()# Configure resolution and apply the hardware transform to keep images uprightconfig = picam2.create_still_configuration(    main={"size": (640, 480)},    transform=Transform(hflip=True, vflip=True) )picam2.configure(config)picam2.start()# Give the sensor 2 seconds to adjust to the room's lightingtime.sleep(2) # Take the picturepicam2.capture_file("test_shot.jpg")print("Success! Picture saved as test_shot.jpg")# Safely shut down the camerapicam2.stop()